"use client";

import {
  motion,
  useScroll,
  useTransform,
  useMotionTemplate,
} from "framer-motion";
import styles from "./Hero.module.css";

export default function Hero() {
  const { scrollY } = useScroll();

  // Фонове зображення: масштаб, розмиття, прозорість
  const scale = useTransform(scrollY, [0, 500], [1, 1.15]);
  const blur = useTransform(scrollY, [0, 500], [0, 8]);
  const opacity = useTransform(scrollY, [0, 500], [1, 0.5]);
  const blurFilter = useMotionTemplate`blur(${blur}px)`;

  // Паралакс тексту (рухається вгору повільніше за скрол)
  const textY = useTransform(scrollY, [0, 500], [0, -100]);

  return (
    <section className={styles.hero}>
      {/* Фоновий шар */}
      <motion.div
        className={styles.background}
        style={{
          scale,
          filter: blurFilter,
          opacity,
          willChange: "transform, filter", // Оптимізація для GPU
        }}
      />

      {/* Контентний шар */}
      <motion.div
        className={styles.left}
        style={{ y: textY }}
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 1, ease: "easeOut" }}
      >
        <p className={styles.intro}>Hello, I am</p>
        <h1 className={styles.title}>Anastasiia Totska</h1>
        <h2 className={styles.role}>Frontend Developer</h2>
        <p className={styles.description}>
          Junior Frontend Developer creating modern, responsive web experiences.
          Always eager to learn and improve.
        </p>
      </motion.div>
    </section>
  );
}
